  ('pukao-6f0ba476-moex-00071', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依遺產及贈與稅法之規定，下列敘述何者錯誤？', '["納稅義務人申請以課徵標的物以外之財產抵繳遺產稅或贈與稅者，其抵繳價值之計算，以申請 日為準", "納稅義務人申請以中華民國境內課徵標的物之財產抵繳遺產稅者，其抵繳價值之計算，以被繼 承人死亡之日之價值為準", "遺產稅之納稅義務人，如有正當理由未能如期申報者，應於被繼承人死亡之日起6個月內以書 面向稽徵機關提出申請延長", "遺產稅之納稅義務人，除有申請延期繳納稅款外，應於稽徵機關送達核定稅額通知書之日起 3 個月內繳清稅款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00072', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '下列有關遺產及贈與稅之申報，下列何者正確？', '["遺產稅低於免稅額時不用申報", "贈與人於一年內贈與他人之財產總額低於免稅額時不用申報", "贈與稅之申報期限為超過免稅額之贈與行為發生後2個月內", "贈與稅在同一年內同一贈與人再次贈與時，不用合併前幾次贈與的金額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
