  ('pukao-6f0ba476-moex-00075', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '所得稅法規定之資產重估價的相關規定何者正確？', '["採用國際會計準則的企業，可以選擇每年以公允價值重估其資產", "採用國際會計準則的企業，當年度公允價值上漲25%時，得辦理資產重估價", "適用資產重估的資產，當年度物價指數較取得年度或前次辦理資產重估價年度物價指數上漲達 25%以上，得辦理資產重估價", "適用資產重估的資產，當年度物價指數較取得年度或前次辦理資產重估價年度物價指數上漲達 20%以上，得辦理資產重估價"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
